const INFERENCE_BASE = $env.INFERENCE_BASE_URL || 'http://host.docker.internal:11434/v1';
const INFERENCE = INFERENCE_BASE + '/chat/completions';
const MLFLOW = 'http://mlflow:5050/api/2.0/mlflow';
const defaultModel = $env.INFERENCE_DEFAULT_MODEL || 'qwen2.5:14b';
const INFERENCE_KEY = $env.LITELLM_API_KEY || '';
const LLM_HEADERS = INFERENCE_KEY ? { Authorization: 'Bearer ' + INFERENCE_KEY } : {};
const body = $input.item.json.body;

// OpenAI-shaped error helper
function oaiError(status, message, type, code) {
  return { _error: true, _status: status, error: { message, type: type || 'invalid_request_error', param: null, code: code || null } };
}

try {
  const model = body.model;
  if (!model) return [{ json: oaiError(400, 'model is required', 'invalid_request_error') }];

  const messages = body.messages || [];
  const stream = body.stream || false;
  const temperature = body.temperature !== undefined ? body.temperature : 0.7;

  // Curated model allowlist from env
  const allowedStr = $env.INFERENCE_ALLOWED_MODELS || "qwen2.5:14b,qwen2.5:7b,qwen3:32b,qwen3:30b,mistral:7b-instruct,llama3.2:latest,nomic-embed-text:latest";
  const ALLOWED = new Set(allowedStr.split(',').map(s => s.trim()).filter(Boolean));

  // Extract last user message
  const lastUserMsg = [...messages].reverse().find(m => m.role === 'user');
  if (!lastUserMsg) return [{ json: oaiError(400, 'No user message found') }];
  const userInput = typeof lastUserMsg.content === 'string'
    ? lastUserMsg.content
    : Array.isArray(lastUserMsg.content)
      ? lastUserMsg.content.filter(c => c.type === 'text').map(c => c.text).join('\n')
      : String(lastUserMsg.content);

  var chatStart = Date.now();

  let response, usage, promptInfo;

  // Try prompt-enhanced path first (MLflow prompt registry)
  try {
    const rmResp = await _get(MLFLOW + '/registered-models/get', {
      params: { name: model }, timeout: 10000
    });
    const rm = rmResp.data.registered_model;
    const aliasEntry = (rm.aliases || []).find(a => a.alias === 'production');
    if (!aliasEntry) throw new Error('No production alias');

    // Canary routing: check if canary is active and roll dice
    var rmTags = {};
    (rm.tags || []).forEach(function(t) { rmTags[t.key] = t.value; });
    var canaryEnabled = rmTags['canary.enabled'] === 'true';
    var selectedVersion = aliasEntry.version;
    var isCanary = false;
    if (canaryEnabled) {
      var canaryPct = Number(rmTags['canary.traffic_pct'] || 0);
      var canaryVer = rmTags['canary.staging_version'] || '';
      if (canaryVer && canaryPct > 0) {
        var useCanary;
        var canarySessionId = body.session_id || '';
        if (canarySessionId) {
          var hash = 0;
          for (var ci = 0; ci < canarySessionId.length; ci++) {
            hash = ((hash << 5) - hash) + canarySessionId.charCodeAt(ci);
            hash = hash & hash;
          }
          useCanary = (Math.abs(hash) % 100) < canaryPct;
        } else {
          useCanary = Math.random() * 100 < canaryPct;
        }
        if (useCanary) {
          selectedVersion = canaryVer;
          isCanary = true;
        }
      }
    }

    // Fix: fetch version directly instead of relying on latest_versions
    const mvResp = await _get(MLFLOW + '/model-versions/get', {
      params: { name: model, version: selectedVersion }, timeout: 10000
    });
    const mv = mvResp.data.model_version;
    const promptTag = (mv.tags || []).find(t => t.key === 'mlflow.prompt.text');
    if (!promptTag) throw new Error('No prompt template');

    // Build variables: explicit body.variables, falling back to {message: userInput}
    const vars = body.variables || { message: userInput };
    if (!vars.message) vars.message = userInput;

    // Render template
    let rendered = promptTag.value;
    for (const [key, value] of Object.entries(vars)) {
      const pattern = new RegExp('\\{\\{\\s*' + key + '\\s*\\}\\}', 'g');
      rendered = rendered.replace(pattern, String(value));
    }

    // Check for unresolved variables
    const unresolved = rendered.match(/\{\{\s*\w+\s*\}\}/g);
    if (unresolved) {
      return [{ json: oaiError(400, 'Unresolved template variables: ' + unresolved.join(', ')) }];
    }

    const ir = await _post(INFERENCE, {
      model: defaultModel,
      messages: [{ role: 'user', content: rendered }],
      temperature
    }, { headers: LLM_HEADERS, timeout: 120000 });

    response = ir.data.choices[0].message.content;
    usage = ir.data.usage || {};
    promptInfo = { name: rm.name, version: selectedVersion, is_canary: isCanary };
  } catch (err) {
    // Fallback: direct pass-through
    if (!ALLOWED.has(model)) return [{ json: oaiError(404, 'Model not available: ' + model, 'invalid_request_error', 'model_not_found') }];
    const or = await _post(INFERENCE, {
      model, messages, temperature, stream: false
    }, { headers: LLM_HEADERS, timeout: 120000 });
    response = or.data.choices[0].message.content;
    usage = or.data.usage || {};
    promptInfo = null;
  }

  var traceId = 'tr_chat_' + Date.now() + '_' + Math.random().toString(36).substr(2, 4);
  var latencyMs = Date.now() - chatStart;
  _post('http://n8n:5678/webhook/traces', {
    action: 'log', trace_id: traceId, source: 'chat',
    model: promptInfo ? defaultModel : body.model,
    prompt_name: promptInfo ? promptInfo.name : null,
    prompt_version: promptInfo ? String(promptInfo.version) : null,
    status: 'ok', latency_ms: latencyMs,
    tokens: { prompt: usage.prompt_tokens || 0, completion: usage.completion_tokens || 0, total: usage.total_tokens || 0 }
  }).catch(function(){});

  const cid = 'chatcmpl-' + Date.now();
  const ts = Math.floor(Date.now() / 1000);
  const fp = promptInfo ? 'fp_' + promptInfo.name + '_v' + promptInfo.version + (promptInfo.is_canary ? '_canary' : '') : 'fp_inference';

  if (stream) {
    // Split response into word-level chunks for more realistic SSE
    const words = response.split(/( +)/);
    const lines = [];
    // Role chunk (no content)
    lines.push('data: ' + JSON.stringify({ id: cid, object: 'chat.completion.chunk', created: ts, model, system_fingerprint: fp, choices: [{ index: 0, delta: { role: 'assistant' }, finish_reason: null }] }));
    // Content chunks — batch ~3 words per chunk
    for (let i = 0; i < words.length; i += 3) {
      const content = words.slice(i, i + 3).join('');
      if (!content) continue;
      lines.push('data: ' + JSON.stringify({ id: cid, object: 'chat.completion.chunk', created: ts, model, system_fingerprint: fp, choices: [{ index: 0, delta: { content }, finish_reason: null }] }));
    }
    // Final chunk
    lines.push('data: ' + JSON.stringify({ id: cid, object: 'chat.completion.chunk', created: ts, model, system_fingerprint: fp, choices: [{ index: 0, delta: {}, finish_reason: 'stop' }], usage: { prompt_tokens: usage.prompt_tokens || 0, completion_tokens: usage.completion_tokens || 0, total_tokens: usage.total_tokens || 0 } }));
    lines.push('data: [DONE]');
    return [{ json: { _error: false, _stream: true, stream_data: lines.join('\n\n') + '\n\n' } }];
  }

  return [{ json: { _error: false, _stream: false, completion: {
    id: cid, object: 'chat.completion', created: ts, model, system_fingerprint: fp,
    choices: [{ index: 0, message: { role: 'assistant', content: response }, finish_reason: 'stop' }],
    usage: { prompt_tokens: usage.prompt_tokens || 0, completion_tokens: usage.completion_tokens || 0, total_tokens: usage.total_tokens || 0 },
    trace_id: traceId
  } } }];
} catch (e) {
  const msg = e.response && e.response.data && e.response.data.error ? e.response.data.error.message : (e.message || String(e));
  const status = (e.response && e.response.status) || 500;
  return [{ json: { _error: true, _status: status, error: { message: msg, type: 'api_error', param: null, code: null } } }];
}

