const INFERENCE_BASE = $env.INFERENCE_BASE_URL || 'http://host.docker.internal:11434/v1';
const INFERENCE_KEY = $env.LITELLM_API_KEY || '';
const LLM_HEADERS = INFERENCE_KEY ? { Authorization: 'Bearer ' + INFERENCE_KEY } : {};
const body = $input.item.json.body;

function oaiError(status, message, type) {
  return { _error: true, _status: status, error: { message, type: type || 'invalid_request_error', param: null, code: null } };
}

try {
  if (!body.input) return [{ json: oaiError(400, 'input is required') }];

  const allowedStr = $env.INFERENCE_ALLOWED_MODELS || "qwen2.5:14b,qwen2.5:7b,qwen3:32b,qwen3:30b,mistral:7b-instruct,llama3.2:latest,nomic-embed-text:latest";
  const ALLOWED = new Set(allowedStr.split(',').map(s => s.trim()).filter(Boolean));
  const model = body.model || 'nomic-embed-text:latest';

  if (!ALLOWED.has(model)) return [{ json: oaiError(404, 'Model not available: ' + model) }];

  const resp = await _post(INFERENCE_BASE + '/embeddings', {
    model,
    input: body.input,
    encoding_format: body.encoding_format || 'float'
  }, { headers: LLM_HEADERS, timeout: 60000 });

  return [{ json: { _error: false, result: resp.data } }];
} catch (e) {
  const msg = e.response && e.response.data && e.response.data.error ? e.response.data.error.message : (e.message || String(e));
  return [{ json: oaiError((e.response && e.response.status) || 500, msg, 'api_error') }];
}
